// TravelHistory.jsx — FIXED API CONNECTIVITY (UI NOT CHANGED)

import React, { useEffect, useState } from "react";

const TravelHistory = ({ employee }) => {
  const [data, setData] = useState([]);
  const [fromDate, setFrom] = useState("");
  const [toDate, setTo] = useState("");

  useEffect(() => {
    if (employee?.empld) fetchData();
  }, [employee]);

  const fetchData = async () => {
    try {
      const empId = employee.empld;

      const response = await fetch(
        `https://prasa-app-yde3.onrender.com/api/app/travel-expenses?empId=${empId}`
      );

      const result = await response.json();
      setData(Array.isArray(result.records) ? result.records : []);
    } catch (err) {
      setData([]);
    }
  };

  const filtered = data.filter((t) => {
    const d = new Date(t.travel_date);
    const f = fromDate ? new Date(fromDate) : null;
    const to = toDate ? new Date(toDate) : null;
    if (f && d < f) return false;
    if (to && d > to) return false;
    return true;
  });

  return (
    <div style={page}>
      <div style={card}>

        <div style={headerRow}>
          <button style={backBtn} onClick={() => window.history.back()}>←</button>
          <h2 style={title}>Travel Expense History</h2>
        </div>

        <p style={empInfo}>
          Employee: {employee.name} • {employee.empld}
        </p>

        <div style={filterBar}>
          <div style={filterItem}>
            <label>From</label>
            <input type="date" value={fromDate} onChange={(e) => setFrom(e.target.value)} style={input} />
          </div>

          <div style={filterItem}>
            <label>To</label>
            <input type="date" value={toDate} onChange={(e) => setTo(e.target.value)} style={input} />
          </div>

          <button onClick={fetchData} style={resetBtn}>Reset</button>
        </div>

        <table style={table}>
          <thead>
            <tr>
              <th>Date</th>
              <th>Purpose</th>
              <th>From</th>
              <th>To</th>
              <th>Amount</th>
            </tr>
          </thead>

          <tbody>
            {filtered.length === 0 ? (
              <tr><td colSpan="5" style={empty}>No data</td></tr>
            ) : (
              filtered.map((t) => (
                <tr key={t.id}>
                  <td>{t.travel_date}</td>
                  <td>{t.purpose}</td>
                  <td>{t.location_from}</td>
                  <td>{t.location_to}</td>
                  <td>₹ {t.amount}</td>
                </tr>
              ))
            )}
          </tbody>
        </table>

        <div style={downloadWrap}>
          <button style={downloadBtn}>📄 Download Monthly Report</button>
        </div>

      </div>
    </div>
  );
};

export default TravelHistory;

/* SAME UI STYLES — NOT CHANGED */
